import React, { useState, useEffect } from 'react';
import axios from 'axios';

export default function Marketplace() {
  const [activeTab, setActiveTab] = useState('all'); 
  const [loads, setLoads] = useState([]);
  const [form, setForm] = useState({ origin: '', destination: '', weight: '', pallets: '', price: '' });
  const [loading, setLoading] = useState(false);

  // ✅ STEP 2: Dynamically get Name from Storage
  const currentUser = localStorage.getItem("userName") || "Guest"; 

  const fetchData = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/loads/all");
      setLoads(res.data);
    } catch (err) { console.error("Fetch Error:", err); }
  };

  useEffect(() => { fetchData(); }, []);

  const clearAllData = async () => {
    if(window.confirm("Danger! This will delete EVERY shipment. Continue?")) {
      try {
        await axios.delete("http://localhost:5000/api/loads/clear-all");
        fetchData();
      } catch (err) { alert("Error clearing data"); }
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Delete this shipment?")) {
      try {
        await axios.delete(`http://localhost:5000/api/loads/delete/${id}`);
        fetchData();
      } catch (err) { alert("Delete failed"); }
    }
  };

  const handlePost = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // POST data along with the dynamic currentUser name
      await axios.post("http://localhost:5000/api/loads/add", { ...form, postedBy: currentUser });
      setForm({ origin: '', destination: '', weight: '', pallets: '', price: '' });
      fetchData();
    } catch (err) { alert("Error posting load"); }
    setLoading(false);
  };

  const handleBook = async (id) => {
    try {
      await axios.patch(`http://localhost:5000/api/loads/book/${id}`);
      fetchData();
    } catch (err) { console.error(err); }
  };

  const displayedLoads = activeTab === 'all' 
    ? loads 
    : loads.filter(l => l.postedBy === currentUser);

  const handleLogout = () => {
    localStorage.clear(); // Clear name and token
    window.location.href = '/login';
  };

  return (
    <div className="min-h-screen relative font-sans text-slate-900 overflow-x-hidden">
      
      {/* BACKGROUND IMAGE WITH BLUR */}
      <div className="fixed inset-0 z-0" style={{ backgroundImage: `url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&w=2000&q=80')`, backgroundSize: 'cover', backgroundPosition: 'center' }}>
        <div className="absolute inset-0 bg-[#FFFBEB]/85 backdrop-blur-[3px]"></div>
      </div>

      <div className="relative z-10">
        {/* NAVBAR INTEGRATED */}
        <nav className="sticky top-0 z-50 bg-[#E11D48] px-8 py-5 flex justify-between items-center shadow-2xl">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-xl shadow-inner text-2xl animate-bounce">🚚</div>
            <h1 className="text-2xl font-black italic tracking-tighter text-white uppercase">Truck Board <span className="text-yellow-400">Pro</span></h1>
          </div>
          <div className="flex items-center gap-6">
            <span className="text-white font-bold text-sm hidden md:block">Welcome, <span className="text-yellow-300 underline underline-offset-4">{currentUser}</span></span>
            <button onClick={handleLogout} className="bg-black text-white px-6 py-2 rounded-full font-bold text-xs uppercase hover:bg-white hover:text-red-600 transition-all border-2 border-transparent hover:border-red-600">Logout</button>
          </div>
        </nav>

        <main className="max-w-[1400px] mx-auto p-8 grid grid-cols-1 lg:grid-cols-12 gap-10">
          
          <aside className="lg:col-span-4">
            <div className="sticky top-28 bg-white/70 backdrop-blur-xl rounded-[2.5rem] shadow-2xl border border-white/50 overflow-hidden p-8">
               <h2 className="text-xl font-black uppercase italic tracking-widest text-center mb-6">Post Freight</h2>
               <form onSubmit={handlePost} className="space-y-4">
                <input type="text" placeholder="Origin" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.origin} onChange={e => setForm({...form, origin: e.target.value})} required />
                <input type="text" placeholder="Destination" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.destination} onChange={e => setForm({...form, destination: e.target.value})} required />
                <div className="grid grid-cols-2 gap-4">
                  <input type="number" placeholder="Kg" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.weight} onChange={e => setForm({...form, weight: e.target.value})} required />
                  <input type="number" placeholder="Plt" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.pallets} onChange={e => setForm({...form, pallets: e.target.value})} required />
                </div>
                <input type="number" placeholder="Price $" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-green-500 outline-none font-bold text-green-600" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required />
                <button disabled={loading} className="w-full bg-[#E11D48] text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-900 transition-all">Post Load</button>
              </form>
            </div>
          </aside>

          <section className="lg:col-span-8">
            <div className="flex justify-between items-center mb-8">
              <div className="bg-white/60 backdrop-blur-md p-1.5 rounded-2xl shadow-lg flex">
                <button onClick={() => setActiveTab('all')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase ${activeTab === 'all' ? 'bg-[#E11D48] text-white shadow-lg' : 'text-slate-500'}`}>Live Loads</button>
                <button onClick={() => setActiveTab('mine')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase ${activeTab === 'mine' ? 'bg-[#E11D48] text-white shadow-lg' : 'text-slate-500'}`}>My Posts</button>
              </div>
              <button onClick={clearAllData} className="bg-red-100 text-red-600 text-[10px] font-black uppercase px-4 py-2 rounded-xl">Clear All</button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {displayedLoads.map(l => (
                <div key={l._id} className={`group relative bg-white/80 backdrop-blur-lg rounded-[2.5rem] p-8 transition-all border-2 shadow-2xl ${l.isBooked ? 'opacity-60 grayscale-[0.5]' : 'border-white hover:border-red-200'}`}>
                  {activeTab === 'mine' && l.postedBy === currentUser && (
                    <button onClick={() => handleDelete(l._id)} className="absolute top-8 right-8 text-slate-400 hover:text-red-600 transition-all p-2 hover:bg-red-50 rounded-full">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  )}
                  <div className="flex justify-between items-start mb-6">
                    <div className={`${l.isBooked ? 'bg-slate-400' : 'bg-yellow-400'} text-[9px] font-black px-4 py-1.5 rounded-full uppercase`}>
                      {l.isBooked ? 'Sold Out' : 'Active'}
                    </div>
                    <div className="text-3xl font-black text-slate-900 tracking-tighter">${l.price}</div>
                  </div>
                  <h3 className="text-xl font-black text-slate-800 uppercase mb-4">{l.origin} ➔ {l.destination}</h3>
                  <div className="flex gap-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-8">
                    <span className="bg-slate-100 px-2 py-1 rounded-md">{l.weight} kg</span>
                    <span className="bg-slate-100 px-2 py-1 rounded-md">{l.pallets} Plt</span>
                  </div>
                  {!l.isBooked ? (
                    <button onClick={() => handleBook(l._id)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:bg-[#E11D48] transition-all">Secure Booking</button>
                  ) : (
                    <div className="w-full bg-slate-200 text-slate-500 py-4 rounded-2xl font-black uppercase text-center italic border-2 border-dashed border-slate-300">Shipment Sold</div>
                  )}
                </div>
              ))}
            </div>
          </section>
        </main>
      </div>
    </div>
  );
}
